VALUES (SEQ_COST_PAGE_RULE.NEXTVAL, 'cost-pinggu-lq', 'masterGrid', 'COLUMN_OVERRIDE', '[{"columnName":"DOCID","visible":true,"editable":false},{"columnName":"GOODSID","visible":true,"editable":false},{"columnName":"GOODSNAME","visible":true,"editable":true,"searchable":true},{"columnName":"GOODSNAME_EN","visible":true,"editable":true},{"columnName":"STRENGTH","visible":true,"editable":true},{"columnName":"CUSTOMID","visible":true,"editable":false},{"columnName":"CUSTOMNAME","visible":true,"editable":true,"searchable":true},{"columnName":"COUNTRY","visible":true,"editable":true},{"columnName":"TRANPOSID","visible":true,"editable":false},{"columnName":"LIVERY","visible":true,"editable":true},{"columnName":"PROJECTNO","visible":true,"editable":true},{"columnName":"APEX_PL","visible":true,"editable":true},{"columnName":"ANNUAL_QTY","visible":true,"editable":true},{"columnName":"YIELD","visible":true,"editable":true},{"columnName":"P_PERPACK","visible":true,"editable":true},{"columnName":"M_PERPACK","visible":true,"editable":true},{"columnName":"S_PERBACK","visible":true,"editable":true},{"columnName":"X_PERBACK","visible":true,"editable":true},{"columnName":"PACKTYPE","visible":true,"editable":true},{"columnName":"TOTAL_YL","visible":true,"editable":false},{"columnName":"TOTAL_FL","visible":true,"editable":false},{"columnName":"TOTAL_BC","visible":true,"editable":false},{"columnName":"TOTAL_COST","visible":true,"editable":false},{"columnName":"OUT_PRICE_RMB","visible":true,"editable":true},{"columnName":"SALEMONEY","visible":true,"editable":false},{"columnName":"JGF_BATCH","visible":true,"editable":false},{"columnName":"COST_PERQP","visible":true,"editable":true},{"columnName":"COST_PERBOX","visible":true,"editable":false},{"columnName":"JGF_PERQP","visible":true,"editable":false},{"columnName":"ML_PERQP","visible":true,"editable":false},{"columnName":"Y_JG_RE","visible":true,"editable":false},{"columnName":"Y_ML","visible":true,"editable":false},{"columnName":"Y_SALE","visible":true,"editable":false},{"columnName":"FMNAME","visible":true,"editable":true},{"columnName":"FMRATE","visible":true,"editable":true},{"columnName":"MEMO","visible":true,"editable":true}]', 0, 0, SYSTIMESTAMP, SYSTIMESTAMP, 'system');

INSERT INTO T_COST_PAGE_RULE (ID, PAGE_CODE, COMPONENT_KEY, RULE_TYPE, RULES, SORT_ORDER, DELETED, CREATE_TIME, UPDATE_TIME, CREATE_BY)
VALUES (SEQ_COST_PAGE_RULE.NEXTVAL, 'cost-pinggu-lq', 'masterGrid', 'VALIDATION', '[]', 0, 0, SYSTIMESTAMP, SYSTIMESTAMP, 'system');

INSERT INTO T_COST_PAGE_RULE (ID, PAGE_CODE, COMPONENT_KEY, RULE_TYPE, RULES, SORT_ORDER, DELETED, CREATE_TIME, UPDATE_TIME, CREATE_BY)
VALUES (SEQ_COST_PAGE_RULE.NEXTVAL, 'cost-pinggu-lq', 'masterGrid', 'CALC', '[
  {"field":"SALEMONEY","expression":"CostPingguLq.OUT_PRICE_RMB * CostPingguLq.APEX_PL * (CostPingguLq.YIELD / 100)","triggerFields":["CostPingguLq.OUT_PRICE_RMB","CostPingguLq.APEX_PL","CostPingguLq.YIELD"]},
  {"field":"JGF_BATCH","expression":"CostPingguLq.SALEMONEY - CostPingguLq.TOTAL_COST","triggerFields":["CostPingguLq.SALEMONEY","CostPingguLq.TOTAL_COST"]},
  {"field":"COST_PERBOX","expression":"CostPingguLq.TOTAL_COST / CostPingguLq.APEX_PL","triggerFields":["CostPingguLq.TOTAL_COST","CostPingguLq.APEX_PL"]},
  {"field":"JGF_PERQP","expression":"CostPingguLq.JGF_BATCH / CostPingguLq.APEX_PL","triggerFields":["CostPingguLq.JGF_BATCH","CostPingguLq.APEX_PL"]},
  {"field":"ML_PERQP","expression":"CostPingguLq.JGF_PERQP - CostPingguLq.COST_PERQP","triggerFields":["CostPingguLq.JGF_PERQP","CostPingguLq.COST_PERQP"]},
  {"field":"Y_JG_RE","expression":"CostPingguLq.JGF_PERQP * CostPingguLq.ANNUAL_QTY","triggerFields":["CostPingguLq.JGF_PERQP","CostPingguLq.ANNUAL_QTY"]},
  {"field":"Y_ML","expression":"CostPingguLq.ML_PERQP * CostPingguLq.ANNUAL_QTY","triggerFields":["CostPingguLq.ML_PERQP","CostPingguLq.ANNUAL_QTY"]},
  {"field":"Y_SALE","expression":"CostPingguLq.ANNUAL_QTY * CostPingguLq.OUT_PRICE_RMB * CostPingguLq.YIELD","triggerFields":["CostPingguLq.ANNUAL_QTY","CostPingguLq.OUT_PRICE_RMB","CostPingguLq.YIELD"]},
  {"field":"TOTAL_YL","expression":"SUM_IF(''CostMaterialLq.COST_BATCH'', \"DTL_USEFLAG == ''原料''\") * (SUM_IF(''CostMaterialLq.COST_BATCH'', \"DTL_USEFLAG == ''原料''\") > 0 ? 1 / 1.13 : 1)","triggerFields":["CostMaterialLq.COST_BATCH","CostMaterialLq.DTL_USEFLAG"],"order":8},
  {"field":"TOTAL_FL","expression":"SUM_IF(''CostMaterialLq.COST_BATCH'', \"DTL_USEFLAG == ''辅料''\") * (SUM_IF(''CostMaterialLq.COST_BATCH'', \"DTL_USEFLAG == ''原料''\") > 0 ? 1 / 1.13 : 1)","triggerFields":["CostMaterialLq.COST_BATCH","CostMaterialLq.DTL_USEFLAG"],"order":9},
  {"field":"TOTAL_BC","expression":"SUM_IF(''CostPackageLq.COST_BATCH'', \"DTL_USEFLAG == ''印字包材'' || DTL_USEFLAG == ''非印字包材''\") * (SUM_IF(''CostMaterialLq.COST_BATCH'', \"DTL_USEFLAG == ''原料''\") > 0 ? 1 / 1.13 : 1)","triggerFields":["CostPackageLq.COST_BATCH","CostPackageLq.DTL_USEFLAG","CostMaterialLq.COST_BATCH","CostMaterialLq.DTL_USEFLAG"],"order":10},
  {"field":"TOTAL_COST","expression":"CostPingguLq.TOTAL_YL + CostPingguLq.TOTAL_FL + CostPingguLq.TOTAL_BC","triggerFields":["CostPingguLq.TOTAL_YL","CostPingguLq.TOTAL_FL","CostPingguLq.TOTAL_BC"],"order":11}
]', 0, 0, SYSTIMESTAMP, SYSTIMESTAMP, 'system');

