  {"field":"BATCH_QTY","formulaField":"CostPackageLq.GOODSNAME","formulas":{"__branch_0":{"key":"桶|说明书|小盒|标签|瓶|盖注射器|适配器|量杯|勺|分度器","expression":"CostPingguLq.APEX_PL / CostPingguLq.P_PERPACK * (1 + CostPackageLq.EXADD_MATER / 100)","triggerFields":["CostPingguLq.APEX_PL","CostPingguLq.P_PERPACK","CostPackageLq.EXADD_MATER"],"matchType":"regex"},"__branch_1":{"key":"大纸箱","expression":"ceil(CostPingguLq.APEX_PL / (CostPingguLq.P_PERPACK * CostPingguLq.S_PERBACK) * (1 + CostPackageLq.EXADD_MATER / 100))","triggerFields":["CostPingguLq.APEX_PL","CostPingguLq.P_PERPACK","CostPingguLq.S_PERBACK","CostPackageLq.EXADD_MATER"],"matchType":"regex"},"__branch_2":{"key":"托盘","expression":"ceil(CostPingguLq.APEX_PL / (CostPingguLq.P_PERPACK * CostPingguLq.S_PERBACK * CostPingguLq.X_PERBACK) * (1 + CostPackageLq.EXADD_MATER / 100))","triggerFields":["CostPingguLq.APEX_PL","CostPingguLq.P_PERPACK","CostPingguLq.S_PERBACK","CostPingguLq.X_PERBACK","CostPackageLq.EXADD_MATER"],"matchType":"regex"}}}
]', 0, 0, SYSTIMESTAMP, SYSTIMESTAMP, 'system');

